#include <stdio.h>
#include <stdlib.h>

void next_permutation(int *a, int n) {
    int i = n - 2;
    while (i >= 0 && a[i] >= a[i + 1]) i--;
    // pivot exists because next permutation is guaranteed
    int j = n - 1;
    while (a[j] <= a[i]) j--;
    int tmp = a[i]; a[i] = a[j]; a[j] = tmp;
    // reverse suffix
    int l = i + 1, r = n - 1;
    while (l < r) {
        tmp = a[l]; a[l] = a[r]; a[r] = tmp;
        l++; r--;
    }
}

int main() {
    int N, K;
    if (scanf("%d %d", &N, &K) != 2) return 0;
    for (int t = 0; t < K; ++t) {
        int *arr = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &arr[i]);
        next_permutation(arr, N);
        for (int i = 0; i < N; ++i) {
            if (i) printf(" ");
            printf("%d", arr[i]);
        }
        printf("\n");
        free(arr);
    }
    return 0;
}

