int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int N, K;
    if (!(cin >> N >> K)) return 0;
    for (int t = 0; t < K; ++t) {
        vector<int> a(N);
        for (int i = 0; i < N; ++i) cin >> a[i];
        // apply next_permutation manually (std::next_permutation works as well)
        int i = N - 2;
        while (i >= 0 && a[i] >= a[i + 1]) --i;
        int j = N - 1;
        while (a[j] <= a[i]) --j;
        swap(a[i], a[j]);
        reverse(a.begin() + i + 1, a.end());
        for (int i = 0; i < N; ++i) {
            if (i) cout << ' ';
            cout << a[i];
        }
        if (t + 1 < K) cout << '\n';
    }
    return 0;
}

