const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
if (input.length === 0) process.exit(0);
const N = input[idx++];
const K = input[idx++];
let outputs = [];
function nextPermutation(arr) {
  let n = arr.length;
  let i = n - 2;
  while (i >= 0 && arr[i] >= arr[i + 1]) i--;
  let j = n - 1;
  while (arr[j] <= arr[i]) j--;
  [arr[i], arr[j]] = [arr[j], arr[i]];
  // reverse suffix
  let l = i + 1, r = n - 1;
  while (l < r) {
    [arr[l], arr[r]] = [arr[r], arr[l]];
    l++; r--;
  }
}
for (let t = 0; t < K; ++t) {
  let perm = input.slice(idx, idx + N);
  idx += N;
  nextPermutation(perm);
  outputs.push(perm.join(' '));
}
